package com.enterprise.auth.exception;

import com.enterprise.auth.dto.ApiResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MfaException.class)
    public ResponseEntity<ApiResponse> handleMfaException(MfaException ex) {
        return ResponseEntity.badRequest().body(new ApiResponse(false, ex.getMessage()));
    }

    @ExceptionHandler(AccountLockedException.class)
    public ResponseEntity<ApiResponse> handleAccountLockedException(AccountLockedException ex) {
        return ResponseEntity.status(HttpStatus.LOCKED).body(new ApiResponse(false, ex.getMessage()));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ApiResponse> handleValidationExceptions(MethodArgumentNotValidException ex) {
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getAllErrors().forEach((error) -> {
            String fieldName = ((FieldError) error).getField();
            String errorMessage = error.getDefaultMessage();
            errors.put(fieldName, errorMessage);
        });
        return ResponseEntity.badRequest().body(new ApiResponse(false, "Validation failed", errors));
    }

    @ExceptionHandler(RuntimeException.class)
    public ResponseEntity<ApiResponse> handleRuntimeException(RuntimeException ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(new ApiResponse(false, "An unexpected error occurred: " + ex.getMessage()));
    }
}

// ==================== Service: BackupCodeService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom;

    @Value("${mfa.backup-codes.count:10}")
    private int backupCodeCount;

    @Value("${mfa.backup-codes.length:8}")
    private int backupCodeLength;

    @Value("${mfa.backup-codes.low-threshold:3}")
    private int lowThreshold;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
        this.secureRandom = new SecureRandom();
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        logger.info("Generating {} backup codes for user: {}", backupCodeCount, user.getUsername());

        backupCodeRepository.deleteByUser(user);
        backupCodeRepository.flush();

        List<String> plainTextCodes = new ArrayList<>();
        List<BackupCode> backupCodeEntities = new ArrayList<>();

        for (int i = 0; i < backupCodeCount; i++) {
            String code = generateSecureCode();
            plainTextCodes.add(code);

            BackupCode backupCode = new BackupCode(passwordEncoder.encode(code), user);
            backupCodeEntities.add(backupCode);
        }

        backupCodeRepository.saveAll(backupCodeEntities);
        logger.info("Successfully generated and stored {} backup codes for user: {}", backupCodeCount, user.getUsername());

        return plainTextCodes;
    }

    @Transactional
    public boolean verifyAndConsumeBackupCode(User user, String code) {
        String normalizedCode = normalizeCode(code);
        List<BackupCode> unusedCodes = backupCodeRepository.findByUserAndUsedFalse(user);

        for (BackupCode backupCode : unusedCodes) {
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);

                long remainingCodes = backupCodeRepository.countUnusedByUser(user);
                logger.info("Backup code used for user: {}. Remaining codes: {}", user.getUsername(), remainingCodes);

                if (remainingCodes <= lowThreshold) {
                    logger.warn("User {} has only {} backup codes remaining. Regeneration recommended.", 
                            user.getUsername(), remainingCodes);
                }

                return true;
            }
        }

        logger.warn("Failed backup code verification attempt for user: {}", user.getUsername());
        return false;
    }

    public long getUnusedCodeCount(User user) {
        return backupCodeRepository.countUnusedByUser(user);
    }

    public long getTotalCodeCount(User user) {
        return backupCodeRepository.findByUser(user).size();
    }

    public boolean isRegenerationRecommended(User user) {
        return getUnusedCodeCount(user) <= lowThreshold;
    }

    @Transactional
    public void revokeAllBackupCodes(User user) {
        logger.info("Revoking all backup codes for user: {}", user.getUsername());
        backupCodeRepository.deleteByUser(user);
    }

    private String generateSecureCode() {
        StringBuilder code = new StringBuilder();
        String characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        for (int i = 0; i < backupCodeLength; i++) {
            if (i > 0 && i % 4 == 0) {
                code.append('-');
            }
            code.append(characters.charAt(secureRandom.nextInt(characters.length())));
        }
        return code.toString();
    }

    private String normalizeCode(String code) {
        return code.toUpperCase().replace("-", "").replace(" ", "");
    }
}

// ==================== Service: TotpService ====================

package com.enterprise.auth.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Service
public class TotpService {

    private static final Logger logger = LoggerFactory.getLogger(TotpService.class);
    private static final int TIME_STEP = 30;
    private static final int CODE_DIGITS = 6;
    private static final String HMAC_ALGORITHM = "HmacSHA1";
    private final SecureRandom secureRandom = new SecureRandom();

    public String generateSecret() {
        byte[] bytes = new byte[20];
        secureRandom.nextBytes(bytes);
        return Base32Encoder.encode(bytes);
    }

    public String generateQrCodeUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP);
    }

    public boolean verifyCode(String secret, String code) {
        try {
            int codeInt = Integer.parseInt(code);
            long timeIndex = Instant.now().getEpochSecond() / TIME_STEP;

            // Check current time step and adjacent ones for clock skew tolerance
            for (int i = -1; i <= 1; i++) {
                int generatedCode = generateTotpCode(secret, timeIndex + i);
                if (generatedCode == codeInt) {
                    return true;
                }
            }
        } catch (NumberFormatException e) {
            logger.warn("Invalid TOTP code format");
        } catch (Exception e) {
            logger.error("Error verifying TOTP code", e);
        }
        return false;
    }

    private int generateTotpCode(String secret, long timeIndex) throws Exception {
        byte[] key = Base32Encoder.decode(secret);
        byte[] data = ByteBuffer.allocate(8).putLong(timeIndex).array();

        Mac mac = Mac.getInstance(HMAC_ALGORITHM);
        mac.init(new SecretKeySpec(key, HMAC_ALGORITHM));
        byte[] hash = mac.doFinal(data);

        int offset = hash[hash.length - 1] & 0x0F;
        int binary = ((hash[offset] & 0x7F) << 24)
                | ((hash[offset + 1] & 0xFF) << 16)
                | ((hash[offset + 2] & 0xFF) << 8)
                | (hash[offset + 3] & 0xFF);

        return binary % (int) Math.pow(10, CODE_DIGITS);
    }

    // Simple Base32 encoder/decoder
    static class Base32Encoder {
        private static final String BASE32_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

        public static String encode(byte[] data) {
            StringBuilder result = new StringBuilder();
            int buffer = 0;
            int bitsLeft = 0;

            for (byte b : data) {
                buffer = (buffer << 8) | (b & 0xFF);
                bitsLeft += 8;
                while (bitsLeft >= 5) {
                    bitsLeft -= 5;
                    result.append(BASE32_CHARS.charAt((buffer >> bitsLeft) & 0x1F));
                }
            }

            if (bitsLeft > 0) {
                result.append(BASE32_CHARS.charAt((buffer << (5 - bitsLeft)) & 0x1F));
            }

            return result.toString();
        }

        public static byte[] decode(String encoded) {
            encoded = encoded.toUpperCase().replace("=", "");
            byte[] result = new byte[encoded.length() * 5 / 8];
            int buffer = 0;
            int bitsLeft = 0;
            int index = 0;

            for (char c : encoded.toCharArray()) {
                int val = BASE32_CHARS.indexOf(c);
                if (val < 0) continue;
                buffer = (buffer << 5) | val;
                bitsLeft += 5;
                if (bitsLeft >= 8) {
                    bitsLeft -= 8;
                    result[index++] = (byte) ((buffer >> bitsLeft) & 0xFF);
                }
            }

            return result;
        }
    }
}

