package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.MfaAuthenticationService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaManagementController {

    private final MfaAuthenticationService mfaAuthenticationService;

    public MfaManagementController(MfaAuthenticationService mfaAuthenticationService) {
        this.mfaAuthenticationService = mfaAuthenticationService;
    }

    @PostMapping("/setup/initiate")
    public ResponseEntity<MfaSetupResponse> initiateMfaSetup(@RequestParam String username) {
        MfaSetupResponse response = mfaAuthenticationService.initiateMfaSetup(username);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/setup/confirm")
    public ResponseEntity<MfaSetupResponse> confirmMfaSetup(@Valid @RequestBody EnableMfaRequest request) {
        MfaSetupResponse response = mfaAuthenticationService.confirmMfaSetup(request);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<MfaSetupResponse> regenerateBackupCodes(@RequestParam String username,
                                                                    @RequestParam String totpCode) {
        MfaSetupResponse response = mfaAuthenticationService.regenerateBackupCodes(username, totpCode);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/backup-codes/status")
    public ResponseEntity<BackupCodeStatusResponse> getBackupCodeStatus(@RequestParam String username) {
        BackupCodeStatusResponse response = mfaAuthenticationService.getBackupCodeStatus(username);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/disable")
    public ResponseEntity<ApiResponse> disableMfa(@RequestParam String username, @RequestParam String totpCode) {
        ApiResponse response = mfaAuthenticationService.disableMfa(username, totpCode);
        return ResponseEntity.ok(response);
    }
}

// ==================== Config: SecurityConfig ====================

package com.enterprise.auth.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(12);
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
                .csrf(AbstractHttpConfigurer::disable)
                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::sameOrigin))
                .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/auth/**").permitAll()
                        .requestMatchers("/api/mfa/**").permitAll()
                        .requestMatchers("/h2-console/**").permitAll()
                        .anyRequest().authenticated()
                );
        return http.build();
    }
}

